class Solution:
    def numberOfSequence(self, n: int, sick: List[int]) -> int:
        from itertools import permutations
        MOD = 10**9 + 7
        sick_set = set(sick)
        uninfected = [i for i in range(n) if i not in sick_set]
        count = 0
        for perm in permutations(uninfected):
            infected = set(sick_set)
            ok = True
            for pos in perm:
                if (pos - 1 in infected) or (pos + 1 in infected):
                    infected.add(pos)
                else:
                    ok = False
                    break
            if ok:
                count += 1
        return count % MOD

