class Solution:
    def numberOfSequence(self, n: int, sick: List[int]) -> int:
        MOD = 10**9 + 7
        m = len(sick)
        total_free = n - m
        fact = [1] * (total_free + 1)
        for i in range(1, total_free + 1):
            fact[i] = fact[i - 1] * i % MOD
        inv_fact = [1] * (total_free + 1)
        inv_fact[total_free] = pow(fact[total_free], MOD - 2, MOD)
        for i in range(total_free, 0, -1):
            inv_fact[i - 1] = inv_fact[i] * i % MOD

        result = fact[total_free]
        left_gap = sick[0]
        right_gap = n - 1 - sick[-1]
        if left_gap > 0:
            result = result * inv_fact[left_gap] % MOD
        if right_gap > 0:
            result = result * inv_fact[right_gap] % MOD
        for i in range(1, m):
            gap = sick[i] - sick[i - 1] - 1
            if gap > 0:
                result = result * inv_fact[gap] % MOD
                result = result * pow(2, gap - 1, MOD) % MOD
        return result % MOD

