var numberOfSequence = function(n, sick) {
    const MOD = 1000000007n;
    const m = sick.length;
    const totalFree = n - m;

    function power(base, exp, mod) {
        base %= mod;
        let result = 1n;
        while (exp > 0n) {
            if (exp & 1n) result = (result * base) % mod;
            base = (base * base) % mod;
            exp >>= 1n;
        }
        return result;
    }

    const fact = new Array(totalFree + 1);
    fact[0] = 1n;
    for (let i = 1; i <= totalFree; i++) {
        fact[i] = (fact[i - 1] * BigInt(i)) % MOD;
    }
    const invFact = new Array(totalFree + 1);
    invFact[totalFree] = power(fact[totalFree], MOD - 2n, MOD);
    for (let i = totalFree; i > 0; i--) {
        invFact[i - 1] = (invFact[i] * BigInt(i)) % MOD;
    }

    let result = fact[totalFree];
    const leftGap = sick[0];
    const rightGap = n - 1 - sick[m - 1];
    if (leftGap > 0) result = (result * invFact[leftGap]) % MOD;
    if (rightGap > 0) result = (result * invFact[rightGap]) % MOD;
    for (let i = 1; i < m; i++) {
        const gap = sick[i] - sick[i - 1] - 1;
        if (gap > 0) {
            result = (result * invFact[gap]) % MOD;
            result = (result * power(2n, BigInt(gap - 1), MOD)) % MOD;
        }
    }
    return Number(result % MOD);
};
